you could try something like this:

```ts
// The shape of your specific API error
interface ApiErrorDetail {
  type: string;
  message: string;
}

interface ApiErrorResponse {
  error: ApiErrorDetail[];
}

import axios, { AxiosError } from 'axios';

// A helper check (Type Guard)
function isApiError(error: any): error is AxiosError<ApiErrorResponse> {
  return axios.isAxiosError(error) && error.response?.data?.error !== undefined;
}

async function fetchData() {
  try {
    const response = await axios.get('/category/123');
  } catch (err) {
    if (isApiError(err)) {
      // TypeScript now knows 'err.response.data' is 'ApiErrorResponse'
      const errorMessage = err.response?.data.error[0].message;
      console.error("API Error:", errorMessage);
    } else if (axios.isAxiosError(err)) {
      // It's an Axios error but NOT from your API (e.g., Network Error)
      console.error("Network/System Error:", err.message);
    } else {
      // Something else entirely (e.g., a synchronous JS crash)
      console.error("Unknown Error:", err);
    }
  }
}
```

